function slashL2(
  address account,
  address group,
  address[] memory electionLessers,
  address[] memory electionGreaters,
  uint256[] memory electionIndices
) public onlyAuthorizedToSlash returns (bool) {
  uint256 penalty = slashed[account];
  require(penalty > 0, "No penalty given by governance");
  slashed[account] = 0;

  ILockedGold lockedGold = getLockedGold();

  lockedGold.slash(
    account,
    penalty,
    address(0),
    0,
    electionLessers,
    electionGreaters,
    electionIndices
  );

  if (group != address(0)) {
    lockedGold.slash(
      group,
      penalty,
      address(0),
      0,
      electionLessers,
      electionGreaters,
      electionIndices
    );
    IValidators validators = getValidators();
    validators.forceDeaffiliateIfValidator(account);
    validators.halveSlashingMultiplier(group);
  }

  emit GovernanceSlashPerformed(account, group, penalty);
  return true;
}

function _claim(
    bytes memory name,
    DNSSEC.RRSetWithSignature[] memory input
) internal returns (bytes32 parentNode, bytes32 labelHash, address addr) {
    (bytes memory data, uint32 inception) = oracle.verifyRRSet(input);

    // Get the first label
    uint256 labelLen = name.readUint8(0);
    labelHash = name.keccak(1, labelLen);

    bytes memory parentName = name.substring(
        labelLen + 1,
        name.length - labelLen - 1
    );

    // Make sure the parent name is enabled
    parentNode = enableNode(parentName);

    bytes32 node = keccak256(abi.encodePacked(parentNode, labelHash));
    if (!RRUtils.serialNumberGte(inception, inceptions[node])) {
        revert StaleProof();
    }
    inceptions[node] = inception;

    bool found;
    (addr, found) = DNSClaimChecker.getOwnerAddress(name, data);
    if (!found) {
        revert NoOwnerRecordFound();
    }

    emit Claim(node, addr, name, inception);
}

function validateRRs(
    RRUtils.SignedSet memory rrset,
    uint16 typecovered
) internal pure returns (bytes memory name) {
    // Iterate over all the RRs
    for (
        RRUtils.RRIterator memory iter = rrset.rrs();
        !iter.done();
        iter.next()
    ) {
        // We only support class IN (Internet)
        if (iter.class != DNSCLASS_IN) {
            revert InvalidClass(iter.class);
        }

        if (name.length == 0) {
            name = iter.name();
        } else {
            // Name must be the same on all RRs. We do things this way to avoid copying the name
            // repeatedly.
            if (
                name.length != iter.data.nameLength(iter.offset) ||
                !name.equals(0, iter.data, iter.offset, name.length)
            ) {
                revert InvalidRRSet();
            }
        }

        // o  The RRSIG RR's Type Covered field MUST equal the RRset's type.
        if (iter.dnstype != typecovered) {
            revert SignatureTypeMismatch(iter.dnstype, typecovered);
        }
    }
}

function executeCollectionStrategyWithTakerAskWithProof(
    OrderStructs.Taker calldata takerAsk,
    OrderStructs.Maker calldata makerBid
)
    external
    pure
    returns (uint256 price, uint256[] memory itemIds, uint256[] calldata amounts, bool isNonceInvalidated)
{
    price = makerBid.price;
    amounts = makerBid.amounts;

    // A collection order can only be executable for 1 itemId but the actual quantity to fill can vary
    if (amounts.length != 1) {
        revert OrderInvalid();
    }

    (uint256 offeredItemId, bytes32[] memory proof) = abi.decode(
        takerAsk.additionalParameters,
        (uint256, bytes32[])
    );
    itemIds = new uint256[](1);
    itemIds[0] = offeredItemId;
    isNonceInvalidated = true;

    bytes32 root = abi.decode(makerBid.additionalParameters, (bytes32));
    bytes32 node = keccak256(abi.encodePacked(offeredItemId));

    // Verify the merkle root for the given merkle proof
    if (!MerkleProofMemory.verify(proof, root, node)) {
        revert MerkleProofInvalid();
    }
}

function mintAllowed(
    address mToken,
    address minter,
    uint mintAmount
) external override returns (uint) {
    // Pausing is a very serious situation - we revert to sound the alarms
    require(!mintGuardianPaused[mToken], "mint is paused");

    // Shh - currently unused
    mintAmount;

    if (!markets[mToken].isListed) {
        return uint(Error.MARKET_NOT_LISTED);
    }

    uint supplyCap = supplyCaps[mToken];
    // Supply cap of 0 corresponds to unlimited supplying
    if (supplyCap != 0) {
        uint totalCash = MToken(mToken).getCash();
        uint totalBorrows = MToken(mToken).totalBorrows();
        uint totalReserves = MToken(mToken).totalReserves();
        // totalSupplies = totalCash + totalBorrows - totalReserves
        uint totalSupplies = sub_(
            add_(totalCash, totalBorrows),
            totalReserves
        );

        uint nextTotalSupplies = add_(totalSupplies, mintAmount);
        require(nextTotalSupplies < supplyCap, "market supply cap reached");
    }

    // Keep the flywheel moving
    updateAndDistributeSupplierRewardsForToken(mToken, minter);
    return uint(Error.NO_ERROR);
}

function recordTokenDescription(address token) external returns (bytes32 id) {
    require(token != address(0), "Invalid token address");

    string memory name;
    string memory symbol;
    uint8 decimals;

    try IERC20Metadata(token).name() returns (string memory _name) {
        name = _name;
    } catch {
        name = "Unknown Token Name";
    }

    try IERC20Metadata(token).symbol() returns (string memory _symbol) {
        symbol = _symbol;
    } catch {
        symbol = "UNKNOWN";
    }

    try IERC20Metadata(token).decimals() returns (uint8 _decimals) {
        decimals = _decimals;
    } catch {
        decimals = 18; // Standard default
    }

    TokenDescription memory tokenDesc =
        TokenDescription({originalToken: token, name: name, symbol: symbol, decimals: decimals});

    id = _generateTokenDescriptionId(tokenDesc);

    signalService.sendSignal(id);

    emit TokenDescriptionRecorded(id, tokenDesc);
}

function sendPayloadToEvm(
    uint16 targetChain,
    address targetAddress,
    bytes memory payload,
    uint256 receiverValue,
    uint256 gasLimit,
    uint16 refundChain,
    address refundAddress
) public payable returns (uint64) {
    require(targetChain == _localChainId, "This mock only support same-chain message passing");
    require(refundChain == _localChainId, "This mock only support same-chain message passing");
    require(receiverValue <= msg.value, "This mock only support same-chain message passing");

    uint64 seq = _seq++;
    IWormholeReceiver(targetAddress).receiveWormholeMessages{value: receiverValue, gas: gasLimit}(
        payload,
        new bytes[](0),
        toUniversalAddress(msg.sender),
        _localChainId,
        keccak256(abi.encode(seq)) // Unrealistic value but sufficient for current tests
    );

    if (msg.value > receiverValue) {
        Address.sendValue(payable(refundAddress), msg.value - receiverValue);
    }

    return seq;
}

function _grantRole(
    uint64 roleId,
    address account,
    uint32 grantDelay,
    uint32 executionDelay
) internal virtual returns (bool) {
    if (roleId == PUBLIC_ROLE) {
        revert AccessManagerLockedRole(roleId);
    }

    bool newMember = _roles[roleId].members[account].since == 0;
    uint48 since;

    if (newMember) {
        since = Time.timestamp() + grantDelay;
        _roles[roleId].members[account] = Access({since: since, delay: executionDelay.toDelay()});
    } else {
        // No setback here. Value can be reset by doing revoke + grant, effectively allowing the admin to perform
        // any change to the execution delay within the duration of the role admin delay.
        (_roles[roleId].members[account].delay, since) = _roles[roleId].members[account].delay.withUpdate(
            executionDelay,
            0
        );
    }

    emit RoleGranted(roleId, account, executionDelay, since, newMember);
    return newMember;
}

function _countOverride(uint256 proposalId, address account, uint8 support) internal virtual returns (uint256) {
    ProposalVote storage proposalVote = _proposalVotes[proposalId];

    if (support > uint8(VoteType.Abstain)) {
        revert GovernorInvalidVoteType();
    }

    if (proposalVote.voteReceipt[account].hasOverridden) {
        revert GovernorAlreadyOverriddenVote(account);
    }

    uint256 snapshot = proposalSnapshot(proposalId);
    uint256 overriddenWeight = VotesExtended(address(token())).getPastBalanceOf(account, snapshot);
    address delegate = VotesExtended(address(token())).getPastDelegate(account, snapshot);
    uint8 delegateCasted = proposalVote.voteReceipt[delegate].casted;

    proposalVote.voteReceipt[account].hasOverridden = true;
    proposalVote.votes[support] += overriddenWeight;
    if (delegateCasted == 0) {
        proposalVote.voteReceipt[delegate].overriddenWeight += SafeCast.toUint208(overriddenWeight);
    } else {
        uint8 delegateSupport = delegateCasted - 1;
        proposalVote.votes[delegateSupport] -= overriddenWeight;
        emit VoteReduced(delegate, proposalId, delegateSupport, overriddenWeight);
    }

    return overriddenWeight;
}

function _getAddLiquidity(uint160 sqrtPriceX96, AddLiquidityParams memory params)
        internal
        view
        override
        returns (bytes memory modify, uint256 liquidity)
    {
        uint256 nativeRefund = _nativeRefund;

        liquidity = LiquidityAmounts.getLiquidityForAmounts(
            sqrtPriceX96,
            TickMath.getSqrtPriceAtTick(params.tickLower),
            TickMath.getSqrtPriceAtTick(params.tickUpper),
            nativeRefund > 0 ? nativeRefund : params.amount0Desired,
            nativeRefund > 0 ? nativeRefund : params.amount1Desired
        );

        return (
            abi.encode(
                ModifyLiquidityParams({
                    tickLower: params.tickLower,
                    tickUpper: params.tickUpper,
                    liquidityDelta: liquidity.toInt256(),
                    salt: params.userInputSalt
                })
            ),
            liquidity
        );
    }

function binarySearch(Observation[65535] storage self, uint32 time, uint32 target, uint16 index, uint16 cardinality)
        internal
        view
        returns (Observation memory beforeOrAt, Observation memory atOrAfter)
    {
        unchecked {
            uint256 left = (index + 1) % cardinality; // oldest observation
            uint256 right = left + cardinality - 1; // newest observation
            uint256 mid;
            while (true) {
                mid = (left + right) / 2;

                beforeOrAt = self[mid % cardinality];

                // we've landed on an uninitialized tick, keep searching higher (more recently)
                if (!beforeOrAt.initialized) {
                    left = mid + 1;
                    continue;
                }

                atOrAfter = self[(mid + 1) % cardinality];

                bool targetAtOrAfter = lte(time, beforeOrAt.blockTimestamp, target);

                // check if we've found the answer!
                if (targetAtOrAfter && lte(time, target, atOrAfter.blockTimestamp)) break;

                if (!targetAtOrAfter) right = mid - 1;
                else left = mid + 1;
            }
        }
    }

function getGroupEpochRewardsBasedOnScore(
  address group,
  uint256 totalEpochRewards,
  uint256 groupScore
) external view returns (uint256) {
  IValidators validators = getValidators();
  // The group must meet the balance requirements for their voters to receive epoch rewards.
  if (!validators.meetsAccountLockedGoldRequirements(group) || votes.active.total <= 0) {
    return 0;
  }

  FixidityLib.Fraction memory votePortion = FixidityLib.newFixedFraction(
    votes.active.forGroup[group].total,
    votes.active.total
  );
  FixidityLib.Fraction memory slashingMultiplier = FixidityLib.wrap(
    validators.getValidatorGroupSlashingMultiplier(group)
  );

  FixidityLib.Fraction memory score = FixidityLib.wrap(groupScore);
  return
    FixidityLib
      .newFixed(totalEpochRewards)
      .multiply(votePortion)
      .multiply(score)
      .multiply(slashingMultiplier)
      .fromFixed();
}

function vote(
  uint256 proposalId,
  uint256 index,
  Proposals.VoteValue value
) external nonReentrant returns (bool) {
  dequeueProposalsIfReady();
  (Proposals.Proposal storage proposal, Proposals.Stage stage) = requireDequeuedAndDeleteExpired(
    proposalId,
    index
  );
  if (!proposal.exists()) {
    return false;
  }

  require(stage == Proposals.Stage.Referendum, "Incorrect proposal state");
  require(value != Proposals.VoteValue.None, "Vote value unset");

  address account = getAccounts().voteSignerToAccount(msg.sender);
  uint256 weight = getLockedGold().getAccountTotalGovernanceVotingPower(account);
  require(weight != 0, "Voter weight zero");

  _vote(
    proposal,
    proposalId,
    index,
    account,
    value == Proposals.VoteValue.Yes ? weight : 0,
    value == Proposals.VoteValue.No ? weight : 0,
    value == Proposals.VoteValue.Abstain ? weight : 0
  );
  return true;
}

function makeMem(
  uint256[] memory values,
  address[] memory destinations,
  bytes memory data,
  uint256[] memory dataLengths,
  address proposer,
  uint256 deposit
) internal view returns (Proposal memory) {
  require(
    values.length == destinations.length && destinations.length == dataLengths.length,
    "Array length mismatch"
  );
  uint256 transactionCount = values.length;

  Proposal memory proposal;
  proposal.proposer = proposer;
  proposal.deposit = deposit;
  // solhint-disable-next-line not-rely-on-time
  proposal.timestamp = now;

  uint256 dataPosition = 0;
  proposal.transactions = new Transaction[](transactionCount);
  for (uint256 i = 0; i < transactionCount; i = i.add(1)) {
    proposal.transactions[i] = Transaction(
      values[i],
      destinations[i],
      data.slice(dataPosition, dataLengths[i])
    );
    dataPosition = dataPosition.add(dataLengths[i]);
  }
  return proposal;
}

function withdraw(uint256 amount) external nonReentrant onlyBeneficiary {
  require(amount > 0, "Requested withdrawal amount must be greater than zero");
  require(liquidityProvisionMet, "Requested withdrawal before liquidity provision is met");

  uint256 releasedAmount;
  if (isRevoked()) {
    releasedAmount = revocationInfo.releasedBalanceAtRevoke;
  } else {
    releasedAmount = getCurrentReleasedTotalAmount();
  }

  require(
    releasedAmount.sub(totalWithdrawn) >= amount,
    "Requested amount is greater than available released funds"
  );
  require(
    maxDistribution >= totalWithdrawn.add(amount),
    "Requested amount exceeds current alloted maximum distribution"
  );
  require(
    getRemainingUnlockedBalance() >= amount,
    "Insufficient unlocked balance to withdraw amount"
  );
  totalWithdrawn = totalWithdrawn.add(amount);
  beneficiary.sendValue(amount);
  if (getRemainingTotalBalance() == 0) {
    emit ReleaseGoldInstanceDestroyed(beneficiary, address(this));
    selfdestruct(refundAddress);
  }
}

function fillSellOrder(
    address seller,
    address contractAddress,
    uint256 tokenId,
    uint256 quantity,
    uint256 price,
    uint256 startTime,
    uint256 expiration,
    uint256 createdAtBlock,
    bytes memory signature,
    address buyer
) external {
    //date checks
    require(_getCancelledBlockNumber(seller,  contractAddress, tokenId) < createdAtBlock, "Does not allow filled order to replay");
    require(block.timestamp >= startTime, "Sell not started");
    require(block.timestamp <= expiration, "Sell has ended");
    //Signature checks
    SellOrder memory sellOrder = SellOrder({
        seller: seller,
        contractAddress: contractAddress,
        tokenId: tokenId,
        quantity: quantity,
        price: price,
        startTime: startTime,
        expiration: expiration,
        createdAtBlock: createdAtBlock
    });
    _signatureChecks(sellOrder, signature);
    //Move nft from seller to buyer
    _transferNFTToBuyer(contractAddress, seller, buyer, tokenId, quantity);
    //Move erc20 from buyer to seller
    _payERC20ToSeller(seller, buyer, price);
}

function _checkValidityMakerAskItemIdsAndAmountsAndPrice(
    OrderStructs.Maker memory makerAsk
) private view returns (uint256 validationCode, uint256[] memory itemIds, uint256[] memory amounts, uint256 price) {
    if (makerAsk.strategyId == 0) {
        itemIds = makerAsk.itemIds;
        amounts = makerAsk.amounts;
        price = makerAsk.price;

        validationCode = _getOrderValidationCodeForStandardStrategy(
            makerAsk.collectionType,
            itemIds.length,
            amounts
        );
    } else {
        itemIds = makerAsk.itemIds;
        amounts = makerAsk.amounts;
        // @dev It should ideally be adjusted by real price
        price = makerAsk.price;

        (, , , , bytes4 strategySelector, , address strategyImplementation) = looksRareProtocol.strategyInfo(
            makerAsk.strategyId
        );

        (bool isValid, bytes4 errorSelector) = IStrategy(strategyImplementation).isMakerOrderValid(
            makerAsk,
            strategySelector
        );

        validationCode = _getOrderValidationCodeForNonStandardStrategies(isValid, errorSelector);
    }
}

function redeemAndAddReserves(
    address _mToken
) external onlyWhitelistedMarkets(_mToken) {
    (
        MErc20Interface mToken,
        EIP20Interface underlyingToken
    ) = _getMTokenAndUnderlying(_mToken);

    uint256 nativeBalanceBefore = address(this).balance;
    uint256 underlyingBalanceBefore = underlyingToken.balanceOf(
        address(this)
    );
    uint256 mTokenBalance = EIP20Interface(_mToken).balanceOf(
        address(this)
    );

    // Note: mWETH will unwrap to native ETH via WETH_UNWRAPPER
    require(
        mToken.redeem(mTokenBalance) == 0,
        "OEVProtocolFeeRedeemer: redemption failed"
    );

    // If we received native ETH (from mWETH), wrap it back to WETH
    uint256 nativeDelta = address(this).balance - nativeBalanceBefore;
    _wrapNativeToWETH(underlyingToken, nativeDelta);

    uint256 amount = underlyingToken.balanceOf(address(this)) -
        underlyingBalanceBefore;
    _addReservesToMToken(mToken, underlyingToken, amount);
}

function latestRoundData()
        external
        view
        returns (
            uint80 roundId,
            int256 answer,
            uint256 startedAt,
            uint256 updatedAt,
            uint80 answeredInRound
        )
    {
        // Get primary price and scale it
        (
            ,
            int256 primaryPrice,
            uint256 primaryTimestamp,

        ) = _getValidatedOracleData(primaryLBTCOracle);

        uint8 primaryDecimals = primaryLBTCOracle.decimals();
        primaryPrice = scalePrice(primaryPrice, primaryDecimals, decimals);

        // Check primary lbtc/btc PoR exchange rate,
        // if out of bounds, fall back to market rate oracle
        if (primaryPrice < lowerBound || primaryPrice > upperBound) {
            // fall back to market rate oracle if primary is out of bounds
            (, primaryPrice, primaryTimestamp, ) = _getValidatedOracleData(
                fallbackLBTCOracle
            );
            uint8 fallbackDecimals = fallbackLBTCOracle.decimals();
            primaryPrice = scalePrice(primaryPrice, fallbackDecimals, decimals);
        }

        return (0, primaryPrice, 0, primaryTimestamp, 0);
    }

function _revertBatchGateway(Batch memory batch) internal view {
    IBatchGateway.Request[] memory requests = new IBatchGateway.Request[](
        batch.lookups.length
    );
    uint256 count;
    for (uint256 i; i < batch.lookups.length; ++i) {
        Lookup memory lu = batch.lookups[i];
        if ((lu.flags & FLAG_DONE) == 0) {
            EIP3668.Params memory p = decodeOffchainLookup(lu.data);
            requests[count++] = IBatchGateway.Request(
                p.sender,
                p.urls,
                p.callData
            );
        }
    }
    if (count > 0) {
        assembly {
            mstore(requests, count) // truncate to number of offchain requests
        }
        revert OffchainLookup(
            address(this),
            batch.gateways,
            abi.encodeCall(IBatchGateway.query, (requests)),
            this.ccipBatchCallback.selector,
            abi.encode(batch)
        );
    }
}

function challengeTask(uint256 taskId) external onlyAggregators {
    Task memory task = tasks[taskId];
    if (taskId > taskNonce) {
        revert TaskDoesNotExist();
    }
    // TODO: configurable timeout
    if (
        (task.state == TaskState.ASSIGNED && task.startBlock + 300 < block.number) ||
        (task.state == TaskState.CHALLENGED && task.startBlock + 600 < block.number)
    ) {
        OperatorSet memory operatorSet = allocationManager.getAllocatedSets(task.operator)[0];
        IStrategy strategy = allocationManager.getAllocatedStrategies(
            task.operator,
            operatorSet
        )[0];

        inferenceServiceManager.slashOperator(
            task.operator,
            task.fee,
            operatorSet.id,
            strategy
        );
    }
    if (task.state != TaskState.COMPLETED) {
        revert TaskStateIncorrect(TaskState.COMPLETED);
    }
    tasks[taskId].state = TaskState.CHALLENGED;
    // TODO: maybe operator address instead of msg.sender?
    emit TaskChallenged(taskId, msg.sender);
}

function _validateAdditionalParametersAndGetOfferedItemIdWithProof(
    address collection,
    bytes calldata makerAdditionalParameters,
    bytes calldata takerAdditionalParameters
) private view returns (uint256) {
    (
        bytes32 messageId,
        bytes memory payload,
        uint256 timestamp,
        bytes memory signature,
        uint256 offeredItemId,
        bytes32[] memory proof
    ) = abi.decode(takerAdditionalParameters, (bytes32, bytes, uint256, bytes, uint256, bytes32[]));

    (bytes32 root, uint256 transferCooldownPeriod) = abi.decode(makerAdditionalParameters, (bytes32, uint256));

    {
        bytes32 node = keccak256(abi.encodePacked(offeredItemId));

        // Verify the merkle root for the given merkle proof
        if (!MerkleProofMemory.verify(proof, root, node)) {
            revert MerkleProofInvalid();
        }
    }

    _verifyReservoirOracle(
        collection,
        offeredItemId,
        transferCooldownPeriod,
        messageId,
        payload,
        timestamp,
        signature
    );

    return offeredItemId;
}

function isMakerOrderValid(
    OrderStructs.Maker calldata makerBid,
    bytes4 functionSelector
) external pure override returns (bool isValid, bytes4 errorSelector) {
    if (
        functionSelector != StrategyCollectionOffer.executeCollectionStrategyWithTakerAskWithProof.selector &&
        functionSelector != StrategyCollectionOffer.executeCollectionStrategyWithTakerAsk.selector
    ) {
        return (isValid, FunctionSelectorInvalid.selector);
    }

    if (makerBid.quoteType != QuoteType.Bid) {
        return (isValid, QuoteTypeInvalid.selector);
    }

    if (makerBid.amounts.length != 1) {
        return (isValid, OrderInvalid.selector);
    }

    _validateAmountNoRevert(makerBid.amounts[0], makerBid.collectionType);

    // If no root is provided or invalid length, it should be invalid.
    // @dev It does not mean the merkle root is valid against a specific itemId that exists in the collection.
    if (
        functionSelector == StrategyCollectionOffer.executeCollectionStrategyWithTakerAskWithProof.selector &&
        makerBid.additionalParameters.length != 32
    ) {
        return (isValid, OrderInvalid.selector);
    }

    isValid = true;
}

function _initializeDiamondCut(address _init, bytes memory _calldata) private {
    if (_init == address(0)) {
        // Non-empty calldata for zero address
        if (_calldata.length != 0) {
            revert NonEmptyCalldata();
        }
    } else {
        // Do not check whether `_init` is a contract since later we check that it returns data.
        (bool success, bytes memory data) = _init.delegatecall(_calldata);
        if (!success) {
            // If the returndata is too small, we still want to produce some meaningful error

            if (data.length < 4) {
                revert DelegateCallFailed(data);
            }

            assembly {
                revert(add(data, 0x20), mload(data))
            }
        }

        // Check that called contract returns magic value to make sure that contract logic
        // supposed to be used as diamond cut initializer.
        if (data.length != 32) {
            revert DelegateCallFailed(data);
        }
        if (abi.decode(data, (bytes32)) != DIAMOND_INIT_SUCCESS_RETURN_VALUE) {
            revert DelegateCallFailed(data);
        }
    }
}

function getAvailableAmount(
    bytes32 _delegationHash,
    address _delegationManager,
    bytes calldata _terms,
    bytes calldata _args
)
    external
    view
    returns (uint256 availableAmount_, bool isNewPeriod_, uint256 currentPeriod_)
{
    (bytes32 hashKey_, uint256 periodAmount_, uint256 periodDuration_, uint256 startDate_) =
        _getValues(_delegationHash, _delegationManager, _terms, _args);

    PeriodicAllowance memory storedAllowance_ = periodicAllowances[hashKey_];
    if (storedAllowance_.startDate != 0) {
        return _getAvailableAmount(storedAllowance_);
    }

    // Not yet initialized; simulate using provided terms.
    PeriodicAllowance memory allowance_ = PeriodicAllowance({
        periodAmount: periodAmount_,
        periodDuration: periodDuration_,
        startDate: startDate_,
        lastTransferPeriod: 0,
        transferredInCurrentPeriod: 0
    });
    return _getAvailableAmount(allowance_);
}

function batchGetAttestationStats(
  bytes32[] calldata identifiersToLookup
) external view returns (uint256[] memory, address[] memory, uint64[] memory, uint64[] memory) {
  require(identifiersToLookup.length > 0, "You have to pass at least one identifier");

  uint256[] memory matches;
  address[] memory addresses;

  (matches, addresses) = batchlookupAccountsForIdentifier(identifiersToLookup);

  uint64[] memory completed = new uint64[](addresses.length);
  uint64[] memory total = new uint64[](addresses.length);

  uint256 currentIndex = 0;
  for (uint256 i = 0; i < identifiersToLookup.length; i = i.add(1)) {
    address[] memory addrs = identifiers[identifiersToLookup[i]].accounts;
    for (uint256 matchIndex = 0; matchIndex < matches[i]; matchIndex = matchIndex.add(1)) {
      addresses[currentIndex] = getAccounts().getWalletAddress(addrs[matchIndex]);
      completed[currentIndex] = identifiers[identifiersToLookup[i]]
        .attestations[addrs[matchIndex]]
        .completed;
      total[currentIndex] = identifiers[identifiersToLookup[i]]
        .attestations[addrs[matchIndex]]
        .requested;
      currentIndex = currentIndex.add(1);
    }
  }

  return (matches, addresses, completed, total);
}

function createCompoundMultipleWinners(
  CompoundPrizePoolConfig memory prizePoolConfig,
  MultipleWinnersBuilder.MultipleWinnersConfig memory prizeStrategyConfig,
  uint8 decimals
) external returns (CompoundPrizePool) {
  CompoundPrizePool prizePool = compoundPrizePoolProxyFactory.create();
  MultipleWinners prizeStrategy = multipleWinnersBuilder.createMultipleWinners(
    prizePool,
    prizeStrategyConfig,
    decimals,
    msg.sender
  );
  prizePool.initialize(
    reserveRegistry,
    _tokens(prizeStrategy),
    prizePoolConfig.maxExitFeeMantissa,
    CTokenInterface(prizePoolConfig.cToken)
  );
  prizePool.setPrizeStrategy(prizeStrategy);
  prizePool.setCreditPlanOf(
    address(prizeStrategy.ticket()),
    prizeStrategyConfig.ticketCreditRateMantissa.toUint128(),
    prizeStrategyConfig.ticketCreditLimitMantissa.toUint128()
  );
  prizePool.transferOwnership(msg.sender);
  emit CompoundPrizePoolWithMultipleWinnersCreated(prizePool, prizeStrategy);
  return prizePool;
}

